############################################################
# Script 01 - GWAS with mrMLM and Result Merging
#
# Purpose:
#   Run multi-locus GWAS using the mrMLM package and merge all
#   "Final result.csv" files into a single GWAS result table.
#
# Expected inputs:
#   - myG.txt      : genotype file in HapMap format
#   - myY.txt      : phenotype file; first column must contain taxa/IDs
#   - myCV_K9.txt  : population structure/covariate file, or NULL
#
# Main outputs:
#   - GWAS_RESULTS/ generated by mrMLM
#   - merged_GWAS_results.csv
#   - merged_GWAS_results.tsv
############################################################


############################################################
# 0. Packages
############################################################

load_package <- function(package_name) {
  if (!requireNamespace(package_name, quietly = TRUE)) {
    stop(
      paste0("Package '", package_name, "' is required but is not installed."),
      call. = FALSE
    )
  }

  suppressPackageStartupMessages(
    library(package_name, character.only = TRUE)
  )
}

load_package("dplyr")
load_package("readr")
load_package("mrMLM")


############################################################
# 1. User configuration
############################################################

# Input files.
genotype_file <- "myG.txt"
phenotype_file <- "myY.txt"
covariates_file <- "myCV_K9.txt"   # Use NULL if no covariates are available.
kinship_file <- NULL               # NULL lets mrMLM estimate the kinship matrix.

# GWAS output directory.
gwas_output_dir <- "GWAS"

# Directory where mrMLM stores the final result files.
# Adjust this if mrMLM creates a different folder structure in your system.
gwas_results_dir <- file.path(gwas_output_dir, "GWAS_RESULTS")

# mrMLM settings.
methods_list <- c(
  "mrMLM",
  "FASTmrMLM",
  "FASTmrEMMA",
  "pLARmEB",
  "pKWmEB",
  "ISIS EM-BLASSO"
)

# Traits are specified by column position in the phenotype file,
# excluding the first ID/taxa column.
traits_list <- c(40:59)

lod_threshold <- 3
population_structure_type <- "Q"
genotype_format <- "Hmp"
ram_gb <- 20
draw_plot <- TRUE
plot_format <- "png"


############################################################
# 2. Helper functions
############################################################

check_input_file <- function(file_path, required = TRUE) {
  if (is.null(file_path)) {
    return(invisible(FALSE))
  }

  if (!file.exists(file_path)) {
    message <- paste0("Input file not found: ", file_path)

    if (required) {
      stop(message, call. = FALSE)
    } else {
      warning(message, call. = FALSE)
      return(invisible(FALSE))
    }
  }

  return(invisible(TRUE))
}

run_mrmlm_gwas <- function(
    genotype_file,
    phenotype_file,
    covariates_file = NULL,
    kinship_file = NULL,
    output_dir,
    methods_list,
    traits_list,
    lod_threshold = 3,
    population_structure_type = "Q",
    genotype_format = "Hmp",
    ram_gb = 20,
    draw_plot = TRUE,
    plot_format = "png"
) {
  check_input_file(genotype_file)
  check_input_file(phenotype_file)
  check_input_file(covariates_file, required = FALSE)

  dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)

  cat("\nStarting GWAS with mrMLM...\n")
  cat("Genotype file:", genotype_file, "\n")
  cat("Phenotype file:", phenotype_file, "\n")
  cat("Covariates file:", ifelse(is.null(covariates_file), "NULL", covariates_file), "\n")
  cat("Output directory:", output_dir, "\n")
  cat("Traits:", paste(traits_list, collapse = ", "), "\n")
  cat("Methods:", paste(methods_list, collapse = ", "), "\n\n")

  mrMLM::mrMLM(
    fileGen = genotype_file,
    filePhe = phenotype_file,
    filePS = covariates_file,
    fileKin = kinship_file,
    PopStrType = population_structure_type,
    Genformat = genotype_format,
    method = methods_list,
    trait = traits_list,
    CriLOD = lod_threshold,
    DrawPlot = draw_plot,
    Plotformat = plot_format,
    dir = output_dir,
    RAM = ram_gb
  )

  cat("\nGWAS completed.\n")
}

merge_mrmlm_final_results <- function(
    results_dir,
    output_csv = "merged_GWAS_results.csv",
    output_tsv = "merged_GWAS_results.tsv"
) {
  if (!dir.exists(results_dir)) {
    stop(
      paste0("Results directory not found: ", results_dir),
      call. = FALSE
    )
  }

  result_files <- list.files(
    path = results_dir,
    pattern = "Final result\\.csv$",
    full.names = TRUE,
    recursive = TRUE
  )

  if (length(result_files) == 0) {
    stop(
      paste0("No files ending in 'Final result.csv' were found in: ", results_dir),
      call. = FALSE
    )
  }

  cat("\nFinal result files detected:\n")
  print(result_files)

  merged_results <- result_files %>%
    lapply(function(file_path) {
      read.csv(
        file_path,
        header = TRUE,
        stringsAsFactors = FALSE,
        check.names = FALSE
      ) %>%
        mutate(Source_file = basename(file_path))
    }) %>%
    bind_rows()

  write.csv(
    merged_results,
    file = output_csv,
    row.names = FALSE
  )

  readr::write_tsv(
    merged_results,
    file = output_tsv,
    na = ""
  )

  cat("\nMerged GWAS results saved to:\n")
  cat(output_csv, "\n")
  cat(output_tsv, "\n")
  cat("Dimensions:", paste(dim(merged_results), collapse = " x "), "\n")

  return(merged_results)
}


############################################################
# 3. Main execution
############################################################

run_mrmlm_gwas(
  genotype_file = genotype_file,
  phenotype_file = phenotype_file,
  covariates_file = covariates_file,
  kinship_file = kinship_file,
  output_dir = gwas_output_dir,
  methods_list = methods_list,
  traits_list = traits_list,
  lod_threshold = lod_threshold,
  population_structure_type = population_structure_type,
  genotype_format = genotype_format,
  ram_gb = ram_gb,
  draw_plot = draw_plot,
  plot_format = plot_format
)

merged_gwas_results <- merge_mrmlm_final_results(
  results_dir = gwas_results_dir,
  output_csv = "merged_GWAS_results.csv",
  output_tsv = "merged_GWAS_results.tsv"
)

############################################################
# End of script
############################################################
